#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
using namespace std;

class Solution {
public:
    bool isValidSudoku(vector<vector<char>>& board) {
        for (int i = 0; i < 9; i++) {
            vector<char> row;
            for (int j = 0; j < 9; j++) {
                if (board[i][j] != '.') {
                    row.push_back(board[i][j]);
                }
            }
            if (row.size() != 9 || row.size() != set<char>(row.begin(), row.end()).size()) {
                return false;
            }
        }
        for (int j = 0; j < 9; j++) {
            vector<char> column;
            for (int i = 0; i < 9; i++) {
                if (board[i][j] != '.') {
                    column.push_back(board[i][j]);
                }
            }
            if (column.size() != 9 || column.size() != set<char>(column.begin(), column.end()).size()) {
                return false;
            }
        }
        for (int i = 0; i < 9; i += 3) {
            for (int j = 0; j < 9; j += 3) {
                vector<char> box;
                for (int k = i; k < i + 3; k++) {
                    for (int l = j; l < j + 3; l++) {
                        if (board[k][l] != '.') {
                            box.push_back(board[k][l]);
                        }
                    }
                }
                if (box.size() != 9 || box.size() != set<char>(box.begin(), box.end()).size()) {
                    return false;
                }
            }
        }
        return true;
    }
};
int main(int argc, char** argv) {
    Solution s;
    vector<vector<char>> board = {{'5','3','.','.','7','.','.','.','.'},
                                   {'6','.','.','1','9','5','.','.','.'},
                                   {'.','9','8','.','.','.','.','6','.'},
                                   {'8','.','.','.','6','.','.','.','3'},
                                   {'4','.','.','8','.','3','.','.','1'},
                                   {'7','.','.','.','2','.','.','.','6'},
                                   {'.','6','.','.','.','.','2','8','.'},
                                   {'.','.','.','4','1','9','.','. ','.'},
                                   {'.','.','.','6','8','.','.','7','9'},
                                   {'.','.','.','.','4','5','.','1','.'}};
    cout << (s.isValidSudoku(board) ? 'true' : 'false') << endl;
    return 0;
}
